&lt;p&gt;Voici un composant :&lt;/p&gt;&lt;pre&gt;&lt;code&gt;function Chronometre() {
  const [secondes, setSecondes] = useState(0);
  useEffect(() =&gt; {
    const interval = setInterval(() =&gt; {
      setSecondes(s =&gt; s + 1);
    }, 1000);
  }, []);
  return &lt;div&gt;{secondes} secondes&lt;/div&gt;;
}&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;Quel problème potentiel ce code peut-il causer ?&lt;/p&gt;

